db_schema:
CREATE TABLE IF NOT EXISTS user_profiles (id INTEGER PRIMARY KEY, user_id INTEGER NOT NULL UNIQUE, nickname TEXT NOT NULL CHECK(length(nickname) BETWEEN 1 AND 30), age_group TEXT NOT NULL CHECK(age_group IN ('20s','30s','40plus')), preferred_tone TEXT NOT NULL CHECK(preferred_tone IN ('casual','detailed')), primary_platform TEXT NOT NULL CHECK(primary_platform IN ('naver','tistory','medium')), created_at TEXT NOT NULL, updated_at TEXT NOT NULL, FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE CASCADE);

CREATE TABLE IF NOT EXISTS style_profiles (id INTEGER PRIMARY KEY, user_id INTEGER NULL, name TEXT NOT NULL CHECK(length(name) BETWEEN 1 AND 40), is_system_preset INTEGER NOT NULL CHECK(is_system_preset IN (0,1)), sample_texts_json TEXT NOT NULL, analyzed_tone_json TEXT NOT NULL, created_at TEXT NOT NULL, updated_at TEXT NOT NULL, FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE CASCADE,
  CHECK((is_system_preset=1 AND user_id IS NULL) OR (is_system_preset=0 AND user_id IS NOT NULL)));

-- Seed: insert exactly 2 system presets (user_id NULL, is_system_preset=1) if missing.
